import{_ as a,o as t,c as b,j as r,a as n,a1 as p}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"圣宣","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/6.套装/圣宣.md","filePath":"4.资源分区/7.物品与装备/6.套装/圣宣.md"}'),s={name:"4.资源分区/7.物品与装备/6.套装/圣宣.md"};function o(d,e,l,i,_,c){return t(),b("div",null,[...e[0]||(e[0]=[r("h1",{id:"圣宣",tabindex:"-1"},[n("圣宣 "),r("a",{class:"header-anchor",href:"#圣宣","aria-label":'Permalink to "圣宣"'},"​")],-1),r("table",{class:"bannerparthead"},[r("tbody",null,[r("tr",{id:"hdr"},[r("td",{class:"runninghead",nowrap:""},"TMD：勿忘尘001D")])])],-1),p('<h1 id="圣宣-1" tabindex="-1">圣宣 <a class="header-anchor" href="#圣宣-1" aria-label="Permalink to &quot;圣宣&quot;">​</a></h1><p>套装：圣宣</p><p>武器：圣宣B+2000<br> 这两把枪令人感到严肃。<br> 死者之哀，死亡之惧，烙印其上。<br> 这是两把体积2的猎枪。枪的左面为黑色右面为白色，反色的线条勾勒出蝴蝶双翅的轮廓。<br> 每一面都有一只黑白的蝴蝶停留在上面，攻击时会震动翅膀。射出的子弹都会变成黑白蝴蝶，落在攻击者身上后会自动消散，但还是会造成伤害。<br> 手持会让人感受到无尽的肃穆。<br> 武器伤害20L 射程150米<br> 特性：高速5 连射 无限子弹<br> 以此武器攻击时，可以选择目标以意志豁免而不通过防御，若如此做，此武器造成精神伤害。<br> 使用这把武器攻击造成伤害后，若受击者没有任何完好的生命，受击者需以意志豁免对那次攻击出目进行一次抵抗，若失败，则会立刻陷入混乱（效果同震慑）状态，这是一个B级的影响心灵来源效果。<br> 如果已经购买了司书战斗手册，则攻击时会获得8加骰。且可以通过该武器使用战斗书页<br> 命中时会附带2点精神伤害。</p><p>护甲：圣宣B+4000<br> 丧服的黑色是为那些哀悼死者的人准备的。<br> 葬礼上需要的是严肃，不需要那些色彩斑斓的配饰。<br> 用蝴蝶为那些长眠于不毛之地的人们献上哀悼吧。<br> 这是一件内层白色外层黑色的西装，衣角用白色线条画着蝴蝶的双翅，穿在身上能听到死者的声音，即使是无意义的呢喃，也会让你保持对死者的尊敬和肃穆。<br> 轻甲17/17<br> 特性：<br> 【防弹】【防能量】<br> 穿戴者受到的任何情绪异常点数降低2点。<br> 穿戴者不会因为伤势而昏迷。<br> 穿戴者可以倾听已死之人的遗言，这意味着你能正常的与灵魂遗留在尸体上的死者进行交流，但若死者灵魂因任何原因不留存于尸体中，则无法进行沟通。<br> 移动时穿戴者会散成无数的黑白蝴蝶，你能如同完美飞行般进行移动，且可以穿过体积不小于2的空隙。</p><p>饰品：圣宣<br> B+3000<br> 这是一口体积5的黑色棺材，摸上去材质非金非木，在棺材板上刻画着一只栩栩如生的黑白蝴蝶。购买需要将该棺材背负或者与棺材具有肢体接触才可获得该物品的好处。<br> 当一具尸体被放入该棺材后，处于棺材中的尸体将因为获得了永恒的宁静而无法被S级及以下的能力复活，将尸体从棺材中取出则可正常复活。棺材中的尸体在经过15分钟后会转化为一只黑白色的蝴蝶。你也可以选择不转化尸体为蝴蝶，而令其恒久的停滞在棺中。<br> 每场影片，棺木至多转化6只黑白蝴蝶。<br> 当你杀死目标后，如果你以圣宣转化了至少6只蝴蝶，则这些蝴蝶会簇拥着目标的尸体将其抬起而放入棺中，蝴蝶的移动速度与你等同。<br> 你获得等同于环绕在你身侧的被转化蝴蝶数目的遮蔽防御。<br> 当你自身死亡后棺材会自动打开并收容自己的尸体，你自身的尸体不会转化为蝴蝶且不会受损。<br> 若有目标不被任何效果影响发自真心的渴望死亡（这死亡不应具有任何前置条件，如：渴望在战斗中被人杀死，无法触发本效果），则你可以直接将其无痛苦的化作黑白蝴蝶，这同样计入转化蝴蝶的次数上限。</p><p>套装效果：</p><p>现在你每部影片可转化的蝴蝶数目增加6只。</p><p>进入战斗后，你可以自由动作对下一次攻击进行一次关于葬礼的宣言。受到你宣言攻击伤害的目标需要以意志豁免对抗你的意志检定，若失败则会被拉入亡蝶葬仪的世界。荒芜的土地，黑白的世界。唯一的生物只有上下纷飞的黑白蝴蝶，但这也不能为这个世界提供任何生气。<br> 作为葬礼的主持人，你需要与其他目标一同进入该异空间。<br> 该异空间的大小为你的敏感范围。<br> 当你处于异空间内，你的技艺可对该异空间内所有人同时生效。<br> 这是一个A级别、时空来源的异空间效果。<br> 你可以主动退出异空间，但若如此做，则这片空间会消散，其他单位会返回原本所处的世界。<br> 进入该异空间的目标会在战斗结束后回归原本的世界。</p><hr><p>Copyright ? 2023 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',10)])])}const m=a(s,[["render",o]]);export{f as __pageData,m as default};
